#include<bits/stdc++.h>
using namespace std;
struct node
{
    int a[251]={0};
    void operator=(const string&b)
    {
        memset(a,0,sizeof(a));
        int len=b.length()-1;
        for(int i=0;i<=len;i++)
        {
            a[i]=b[len-i]-'0';
        }
    }
    void operator=(const int&b)
    {
        memset(a,0,sizeof(a));
        int x=b,len=0;
        while(x)
        {
            a[len++]=x%10;
            x/=10;
        }
    }
    node operator*(const node&b)const
    {
        node c;
        for(int i=0;i<=100;i++)
        {
            for(int j=0;j<=100;j++)
            {
                c.a[i+j]+=a[i]*b.a[j];
            }
        }
        for(int i=0;i<=200;i++)
        {
            c.a[i+1]+=c.a[i]/10;
            c.a[i]%=10;
        }
        return c;
    }
    node operator*(const int&b)const
    {
        node c;
        for(int i=0;i<=100;i++)
        {
            c.a[i]=a[i]*b;
        }
        for(int i=0;i<=100;i++)
        {
            c.a[i+1]+=c.a[i]/10;
            c.a[i]%=10;
        }
        return c;
    }
    void print()
    {
        int flag=0;
        for(int i=200;i>=0;i--)
        {
            if(a[i]!=0)
            {
                flag=1;
            }
            if(flag)
            {
                printf("%d",a[i]);
            }
        }
    }
    friend void operator*=(node &a,const node&b)
    {
        a=a*b;
    }
    friend void operator*=(node &a,const int&b)
    {
        a=a*b;
    }
}a,l,q,p,r;
int main()
{
    string str;
    int K;
    cin>>str>>K;
    a=str;
    l=1;
    q=a;
    for(int i=1;i<=K;i++)
    {
        p=a;
        r=1;
        int flag=0;
        for(int j=1;j<=10;j++)
        {
            p*=q;
            r*=q;
            if(p.a[i-1]==a.a[i-1])
            {
                q=r;
                l*=j;
                flag=1;
                break;
            }
        }
        if(!flag)
        {
            printf("-1");
            return 0;
        }
    }
    l.print();
    return 0;
}
